            const devBypass = window.localStorage.getItem('cq_dev_bypass_waitlist')
            if (devBypass === 'lab3') {
                return
            }
        }
        // Default: lock everything behind the waitlist home at '/'
        if (location.pathname !== '/') {
            throw redirect({ to: '/' })
        }
    },
    component: () => <Outlet />,
})

