                        >
                            Go to Login
                        </a>
                        <a
                            href="/dashboard"
                            className="inline-flex items-center justify-center rounded-md border border-border bg-secondary px-4 py-2 text-xs font-medium text-secondary-foreground shadow-sm hover:bg-secondary/80"
                        >
